import React, { useEffect, useState } from 'react';
import './Hero.css';

const Hero = ({ 
  title = "WEB", 
  subtitle = "DEVELOPER", 
  backgroundImage = "https://images.unsplash.com/photo-1489599808426-7b0a4a0a0a0a?ixlib=rb-4.0.3&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D&auto=format&fit=crop&w=2070&q=80",
  backgroundVideo = null, // New prop for YouTube video URL
  scrollTarget = "#content",
  typingStrings = ["DESIGNER", "DEVELOPER", "CREATIVE"]
}) => {
  const [imageLoaded, setImageLoaded] = useState(false);
  const [imageError, setImageError] = useState(false);
  const [videoLoaded, setVideoLoaded] = useState(false);
  const [videoError, setVideoError] = useState(false);

  // Extract YouTube video ID from URL
  const getYouTubeVideoId = (url) => {
    if (!url) return null;
    const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=)([^#&?]*).*/;
    const match = url.match(regExp);
    return (match && match[2].length === 11) ? match[2] : null;
  };

  const videoId = backgroundVideo ? getYouTubeVideoId(backgroundVideo) : null;

  // Test image loading
  useEffect(() => {
    const testImage = new Image();
    testImage.onload = () => {
      setImageLoaded(true);
      setImageError(false);
      console.log('Background image loaded successfully:', backgroundImage);
    };
    testImage.onerror = () => {
      setImageError(true);
      setImageLoaded(false);
      console.error('Background image failed to load:', backgroundImage);
    };
    testImage.src = backgroundImage;
  }, [backgroundImage]);

  // Test video loading
  useEffect(() => {
    if (videoId) {
      setVideoLoaded(true);
      setVideoError(false);
      console.log('YouTube video ID extracted:', videoId);
    } else if (backgroundVideo) {
      setVideoError(true);
      setVideoLoaded(false);
      console.error('Invalid YouTube URL:', backgroundVideo);
    }
  }, [videoId, backgroundVideo]);

  useEffect(() => {
    let mounted = true;
    let typingInstance = null;

    const loadScripts = () => {
      return new Promise((resolve) => {
        // Check if scripts are already loaded
        if (typeof window.$ !== 'undefined' && typeof window.Typed !== 'undefined') {
          resolve();
          return;
        }

        // Load jQuery first
        if (typeof window.$ === 'undefined') {
          const jqueryScript = document.createElement('script');
          jqueryScript.src = 'https://code.jquery.com/jquery-3.6.0.min.js';
          jqueryScript.onload = () => {
            // Wait a bit for jQuery to initialize
            setTimeout(() => {
              // Load Typed.js after jQuery
              const typedScript = document.createElement('script');
              typedScript.src = 'https://cdn.jsdelivr.net/npm/typed.js@2.0.12';
              typedScript.onload = () => {
                // Wait a bit for Typed.js to initialize
                setTimeout(() => {
                  resolve();
                }, 100);
              };
              typedScript.onerror = () => {
                console.warn('Failed to load Typed.js, falling back to static text');
                resolve();
              };
              document.head.appendChild(typedScript);
            }, 100);
          };
          jqueryScript.onerror = () => {
            console.warn('Failed to load jQuery, falling back to static text');
            resolve();
          };
          document.head.appendChild(jqueryScript);
        } else {
          resolve();
        }
      });
    };

    const initializeTyping = () => {
      if (!mounted) return;
      
      // Check if the element exists
      const targetElement = document.querySelector('.p2');
      if (!targetElement) {
        console.warn('Target element .p2 not found');
        return;
      }

      if (window.$ && window.Typed) {
        try {
          // Destroy existing instance if any
          if (typingInstance) {
            typingInstance.destroy();
          }
          
          // Initialize Typed.js
          typingInstance = new window.Typed('.p2', {
            strings: typingStrings,
            typeSpeed: 50,
            backSpeed: 10,
            backDelay: 2000,
            showCursor: false,
            loop: false
          });
        } catch (error) {
          console.warn('Typed.js initialization failed:', error);
          // Add fallback class for CSS animation
          targetElement.classList.add('typing-fallback');
        }
      } else {
        console.warn('jQuery or Typed.js not available, using fallback animation');
        // Add fallback class for CSS animation
        targetElement.classList.add('typing-fallback');
      }
    };

    const initializeScrollButton = () => {
      if (!mounted) return;

      try {
        // Use native scroll instead of jQuery for better reliability
        const scrollButton = document.querySelector('.hero-down');
        if (scrollButton) {
          scrollButton.addEventListener('click', function(e) {
            e.preventDefault();
            const targetId = this.getAttribute('href').substring(1);
            const targetElement = document.getElementById(targetId);
            
            if (targetElement) {
              targetElement.scrollIntoView({
                behavior: 'smooth',
                block: 'start'
              });
            }
          });

          // Button animation
          scrollButton.addEventListener('mousedown', function() {
            const btnReact = document.querySelector('.btn-react');
            if (btnReact && window.gsap) {
              window.gsap.fromTo('.btn-react', 0.25, {
                opacity: 0,
                scale: 0
              }, {
                opacity: 0.25,
                scale: 1,
                onComplete: function() {
                  window.gsap.to('.btn-react', 0.25, {
                    opacity: 0,
                    scale: 0
                  });
                }
              });
            }
          });
        }
      } catch (error) {
        console.warn('Scroll button initialization failed:', error);
      }
    };

    // Load scripts and initialize
    loadScripts().then(() => {
      if (mounted) {
        // Add a delay to ensure DOM is ready
        setTimeout(() => {
          initializeTyping();
          initializeScrollButton();
        }, 200);
      }
    });

    return () => {
      mounted = false;
      if (typingInstance) {
        try {
          typingInstance.destroy();
        } catch (error) {
          console.warn('Error destroying typing instance:', error);
        }
      }
    };
  }, [typingStrings]);

  return (
    <div className="hero-section">
      <section className="hero">
        {/* YouTube Video Background */}
        {videoId && videoLoaded && !videoError && (
          <div className="hero-video-container">
            <iframe
              className="hero-video"
              src={`https://www.youtube.com/embed/${videoId}?autoplay=1&mute=1&loop=1&playlist=${videoId}&controls=0&showinfo=0&rel=0&iv_load_policy=3&modestbranding=1&start=0&end=0&fs=0&cc_load_policy=0&disablekb=1&enablejsapi=1&origin=${window.location.origin}`}
              title="Hero Background Video"
              frameBorder="0"
              allow="autoplay; encrypted-media"
              allowFullScreen
            />
          </div>
        )}

        {/* Fallback Image Background */}
        {(!videoId || videoError || !videoLoaded) && (
          <div 
            className="hero-image-container"
            style={{ 
              backgroundImage: imageLoaded ? `url(${backgroundImage})` : 'none',
              backgroundSize: 'cover',
              backgroundPosition: 'center',
              backgroundRepeat: 'no-repeat',
              backgroundAttachment: 'fixed'
            }}
          />
        )}

        {/* Debug info - remove in production */}
        {process.env.NODE_ENV === 'development' && (
          <div style={{
            position: 'absolute',
            top: '10px',
            left: '10px',
            background: 'rgba(0,0,0,0.7)',
            color: 'white',
            padding: '5px 10px',
            fontSize: '12px',
            zIndex: 1000
          }}>
            Video: {videoLoaded ? 'Loaded' : 'Loading...'} | 
            Video Error: {videoError ? 'Yes' : 'No'} | 
            Image: {imageLoaded ? 'Loaded' : 'Loading...'} | 
            Image Error: {imageError ? 'Yes' : 'No'}
          </div>
        )}
        
        <div className="inner-text">
          <p className="p1">{title}</p>
          <p className="p2">{subtitle}</p>
        </div>
        <a 
          className="hero-down" 
          href={scrollTarget}
          onClick={(e) => {
            e.preventDefault();
            const targetElement = document.querySelector(scrollTarget);
            if (targetElement) {
              targetElement.scrollIntoView({
                behavior: 'smooth',
                block: 'start'
              });
            }
          }}
        >
          <div className="btn-react"></div>
          <i className="fa fa-chevron-down"></i>
        </a>
      </section>
    </div>
  );
};

export default Hero;
